import pandas as pd; import numpy as np; from itertools import combinations; df = pd.read_csv('{inputs.descriptor_csv}'); descriptors = [col for col in df.columns if col not in ['label', 'molecule_id']]; descriptor_groups = {'physicochemical': [d for d in descriptors if any(x in d.lower() for x in ['mw', 'logp', 'hbd', 'hba', 'rtb'])], 'topological': [d for d in descriptors if any(x in d.lower() for x in ['tpsa', 'rings', 'aromatic'])], 'electronic': [d for d in descriptors if any(x in d.lower() for x in ['charge', 'dipole', 'homo', 'lumo'])]}; results = []; baseline_preds = (df[descriptors].sum(axis=1) > df[descriptors].sum(axis=1).median()).astype(int); 
for group_name, group_cols in descriptor_groups.items():
  if not group_cols: continue
  ablated_df = df.copy(); ablated_df[group_cols] = 0; ablated_preds = (ablated_df[descriptors].sum(axis=1) > ablated_df[descriptors].sum(axis=1).median()).astype(int); changes = (baseline_preds != ablated_preds).sum(); change_rate = changes / len(df); results.append({'descriptor_group': group_name, 'num_descriptors': len(group_cols), 'molecules_with_label_change': int(changes), 'prediction_change_rate': round(change_rate, 4)});
results_df = pd.DataFrame(results); results_df.to_csv('{task_id}_descriptor_ablation_analysis.csv', index=False); print(results_df.to_string())
